     1→import express from 'express';
     2→import { resolve, dirname } from 'node:path';
     3→import { fileURLToPath } from 'node:url';
     4→import type { PipelineManager } from '../pipeline/manager.js';
     5→import type { StateStore } from '../state/store.js';
     6→import { createApiRouter } from './api-routes.js';
     7→import { createMcpHandler } from '../mcp/server.js';
     8→
     9→const __dirname = dirname(fileURLToPath(import.meta.url));
    10→
    11→export function createApp(store: StateStore, pipeline: PipelineManager) {
    12→  const app = express();
    13→
    14→  // CORS — allow requests from Jira and any origin (local tool, not public)
    15→  // Access-Control-Allow-Private-Network is required by Chrome's Private Network
    16→  // Access policy when a public origin (e.g. atlassian.net) fetches localhost.
    17→  app.use((_req, res, next) => {
    18→    res.header('Access-Control-Allow-Origin', '*');
    19→    res.header('Access-Control-Allow-Methods', 'GET, POST, DELETE, OPTIONS');
    20→    res.header('Access-Control-Allow-Headers', 'Content-Type');
    21→    res.header('Access-Control-Allow-Private-Network', 'true');
    22→    if (_req.method === 'OPTIONS') { res.sendStatus(204); return; }
    23→    next();
    24→  });
    25→
    26→  app.use(express.json());
    27→
    28→  // Request logging (after JSON parsing so body is available)
    29→  app.use((req, _res, next) => {
    30→    // Skip noisy polling requests and MCP traffic
    31→    if (req.method === 'GET' && req.url === '/tasks') { next(); return; }
    32→    if (req.url === '/mcp') { next(); return; }
    33→    console.log(`${req.method} ${req.originalUrl}`);
    34→    if (req.method === 'POST' && req.body) {
    35→      console.log(`  Body: ${JSON.stringify(req.body).slice(0, 300)}`);
    36→    }
    37→    next();
    38→  });
    39→
    40→  // MCP endpoint — Claude Code connects here to call back into the pipeline
    41→  const mcpHandler = createMcpHandler(pipeline);
    42→  app.all('/mcp', (req, res) => { void mcpHandler(req, res); });
    43→
    44→  // API routes
    45→  app.use('/api', createApiRouter(store, pipeline));
    46→
    47→  // Serve static dashboard
    48→  app.use(express.static(resolve(__dirname, 'public')));
    49→
    50→  return app;
    51→}
