     1→const API_BASE = '';
     2→let ws = null;
     3→let tasks = [];
     4→
     5→async function fetchTasks() {
     6→  try {
     7→    const res = await fetch(`${API_BASE}/api/tasks`);
     8→    tasks = await res.json();
     9→    render();
    10→  } catch (err) {
    11→    console.error('Failed to fetch tasks:', err);
    12→  }
    13→}
    14→
    15→function connectWs() {
    16→  const protocol = location.protocol === 'https:' ? 'wss:' : 'ws:';
    17→  ws = new WebSocket(`${protocol}//${location.host}/ws`);
    18→
    19→  ws.onopen = () => {
    20→    document.getElementById('ws-status').textContent = 'Connected';
    21→    document.getElementById('ws-status').className = 'connected';
    22→  };
    23→
    24→  ws.onclose = () => {
    25→    document.getElementById('ws-status').textContent = 'Disconnected';
    26→    document.getElementById('ws-status').className = 'disconnected';
    27→    setTimeout(connectWs, 3000);
    28→  };
    29→
    30→  ws.onmessage = (event) => {
    31→    const msg = JSON.parse(event.data);
    32→    handleWsMessage(msg);
    33→  };
    34→}
    35→
    36→function handleWsMessage(msg) {
    37→  if (msg.type === 'task-created' || msg.type === 'task-status-changed' || msg.type === 'task-completed') {
    38→    const idx = tasks.findIndex(t => t.key === msg.task.key);
    39→    if (idx >= 0) {
    40→      tasks[idx] = msg.task;
    41→    } else {
    42→      tasks.push(msg.task);
    43→    }
    44→    render();
    45→  }
    46→}
    47→
    48→function render() {
    49→  const queued = tasks.filter(t => t.status === 'queued');
    50→  const inProgress = tasks.filter(t => t.status === 'in-progress');
    51→  const completed = tasks.filter(t => t.status === 'completed');
    52→  const failed = tasks.filter(t => t.status === 'failed');
    53→
    54→  document.getElementById('queued-tasks').innerHTML = queued.map(taskCard).join('');
    55→  document.getElementById('in-progress-tasks').innerHTML = inProgress.map(taskCard).join('');
    56→  document.getElementById('completed-tasks').innerHTML = completed.map(taskCard).join('');
    57→  document.getElementById('failed-tasks').innerHTML = failed.map(taskCard).join('');
    58→
    59→  document.getElementById('task-counts').textContent =
    60→    `${queued.length} queued | ${inProgress.length} running | ${completed.length} done | ${failed.length} failed`;
    61→}
    62→
    63→function taskCard(task) {
    64→  let meta = `<span>${task.priority}</span><span>${task.issueType}</span>`;
    65→
    66→  if (task.prUrl) {
    67→    meta += `<a href="${task.prUrl}" target="_blank">View PR</a>`;
    68→  }
    69→  if (task.claudeCostUsd) {
    70→    meta += `<span>$${task.claudeCostUsd.toFixed(2)}</span>`;
    71→  }
    72→
    73→  let extra = '';
    74→  if (task.status === 'failed' && task.errorMessage) {
    75→    extra = `<div class="error-msg">${escapeHtml(task.errorMessage)}</div>`;
    76→    extra += `<button class="btn" onclick="retryTask('${task.key}')">Retry</button>`;
    77→  }
    78→
    79→  return `
    80→    <div class="task-card status-${task.status}">
    81→      <div class="task-key">${escapeHtml(task.key)}</div>
    82→      <div class="task-summary">${escapeHtml(task.summary)}</div>
    83→      <div class="task-meta">${meta}</div>
    84→      ${extra}
    85→    </div>
    86→  `;
    87→}
    88→
    89→async function retryTask(key) {
    90→  try {
    91→    await fetch(`${API_BASE}/api/tasks/${key}/retry`, { method: 'POST' });
    92→  } catch (err) {
    93→    console.error('Failed to retry task:', err);
    94→  }
    95→}
    96→
    97→function escapeHtml(str) {
    98→  const div = document.createElement('div');
    99→  div.textContent = str;
   100→  return div.innerHTML;
   101→}
   102→
   103→fetchTasks();
   104→connectWs();
   105→

