  // ── About overlay ──────────────────────────────────────────────────────────

  /** @type {HTMLElement|null} */
  let aboutOverlay = null;

  function showAboutOverlay() {
    if (aboutOverlay) return; // already open

    const overlay = document.createElement('div');
    overlay.className = 'jiranimo-about-overlay';

    overlay.innerHTML = `
      <div class="jiranimo-about-modal" role="dialog" aria-modal="true" aria-label="About Jiranimo">
        <button class="jiranimo-about-close" title="Close (Esc)">&times;</button>
        <div class="jiranimo-about-logo">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
            <path fill-rule="evenodd" d="M9 4.5a.75.75 0 01.721.544l.813 2.846a3.75 3.75 0 002.576 2.576l2.846.813a.75.75 0 010 1.442l-2.846.813a3.75 3.75 0 00-2.576 2.576l-.813 2.846a.75.75 0 01-1.442 0l-.813-2.846a3.75 3.75 0 00-2.576-2.576l-2.846-.813a.75.75 0 010-1.442l2.846-.813A3.75 3.75 0 007.466 7.89l.813-2.846A.75.75 0 019 4.5zM18 1.5a.75.75 0 01.728.568l.258 1.036c.236.94.97 1.674 1.91 1.91l1.036.258a.75.75 0 010 1.456l-1.036.258c-.94.236-1.674.97-1.91 1.91l-.258 1.036a.75.75 0 01-1.456 0l-.258-1.036a2.625 2.625 0 00-1.91-1.91l-1.036-.258a.75.75 0 010-1.456l1.036-.258a2.625 2.625 0 001.91-1.91l.258-1.036A.75.75 0 0118 1.5zM16.5 15a.75.75 0 01.712.513l.394 1.183c.15.447.5.799.948.948l1.183.395a.75.75 0 010 1.422l-1.183.395c-.447.15-.799.5-.948.948l-.395 1.183a.75.75 0 01-1.422 0l-.395-1.183a1.5 1.5 0 00-.948-.948l-1.183-.395a.75.75 0 010-1.422l1.183-.395c.447-.15.799-.5.948-.948l.395-1.183A.75.75 0 0116.5 15z" clip-rule="evenodd"/>
          </svg>
          <h2>Jiranimo</h2>
        </div>
        <p class="jiranimo-about-version">Version 1.0.0</p>
        <p>Implement Jira tasks with Claude Code — click the sparkle icon on any card to have Claude automatically implement the task, open a draft PR, and update Jira.</p>
        <div class="jiranimo-about-shortcuts">
          <h3>Keyboard shortcuts</h3>
          <div class="jiranimo-about-shortcut-row">
            <span>Open this overlay</span>
            <kbd>⌘E</kbd>
          </div>
          <div class="jiranimo-about-shortcut-row">
            <span>Close overlay</span>
            <kbd>Esc</kbd>
          </div>
        </div>
      </div>
    `;

    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) closeAboutOverlay();
    });

    overlay.querySelector('.jiranimo-about-close').addEventListener('click', closeAboutOverlay);

    document.body.appendChild(overlay);
    aboutOverlay = overlay;
    log('About overlay opened');
  }

  function closeAboutOverlay() {
    if (!aboutOverlay) return;
    aboutOverlay.remove();
    aboutOverlay = null;
    log('About overlay closed');
  }

  document.addEventListener('keydown', (e) => {
    if (e.key === 'e' && e.metaKey && !e.shiftKey && !e.altKey && !e.ctrlKey) {
      e.preventDefault();
      if (aboutOverlay) {
        closeAboutOverlay();
      } else {
        showAboutOverlay();
      }
